use std::cmp::max;

fn solve(s: String) -> i64 {
    let s_chars: Vec<char> = s.chars().collect();
    let n = s_chars.len();

    if n == 0 {
        return 0;
    }

    let mut R_T = vec![0; n + 1];
    R_T[n] = 0;
    for i in (0..n).rev() {
        R_T[i] = R_T[i + 1];
        if s_chars[i] == 'T' {
            R_T[i] += 1;
        }
    }

    let mut prefix_L = vec![0; n + 1];
    prefix_L[0] = 0;
    for i in 0..n {
        prefix_L[i + 1] = prefix_L[i];
        if s_chars[i] == 'L' {
            prefix_L[i + 1] += 1;
        }
    }

    let mut base: i64 = 0;
    for j in 0..n {
        if s_chars[j] == 'C' {
            base += (prefix_L[j] as i64) * (R_T[j + 1] as i64);
        }
    }

    let mut G = vec![0_i64; n + 1];
    G[n] = 0;
    for j in (0..n).rev() {
        G[j] = G[j + 1];
        if s_chars[j] == 'C' {
            G[j] += R_T[j + 1] as i64;
        }
    }

    let mut H1 = vec![0_i64; n + 1];
    for p in 0..=n {
        H1[p] = (prefix_L[p] as i64) * (R_T[p] as i64);
    }

    let mut prefix_LC = vec![0_i64; n + 1];
    let mut countL: i64 = 0;
    for i in 0..n {
        match s_chars[i] {
            'L' => {
                countL += 1;
                prefix_LC[i + 1] = prefix_LC[i];
            },
            'C' => {
                prefix_LC[i + 1] = prefix_LC[i] + countL;
            },
            _ => {
                prefix_LC[i + 1] = prefix_LC[i];
            }
        }
    }

    let mut max_gain: i64 = 0;
    for p in 0..=n {
        let gain = max(G[p], max(H1[p], prefix_LC[p]));
        if gain > max_gain {
            max_gain = gain;
        }
    }

    base + max_gain
}
