func solve(s: String) -> Int64 {
    let n = s.count
    if n == 0 {
        return 0
    }
    let sArr = Array(s)
    var prefix_L = [Int64](repeating: 0, count: n+1)
    var prefix_LC = [Int64](repeating: 0, count: n+1)
    var base_countL: Int64 = 0
    var base_countLC: Int64 = 0
    var base_total: Int64 = 0

    for i in 0..<n {
        let char = sArr[i]
        if char == "L" {
            base_countL += 1
        } else if char == "C" {
            base_countLC += base_countL
        } else if char == "T" {
            base_total += base_countLC
        }
        prefix_L[i+1] = base_countL
        prefix_LC[i+1] = base_countLC
    }

    var suffix_T = [Int64](repeating: 0, count: n+1)
    var countT_temp: Int64 = 0
    for i in (0..<n).reversed() {
        if sArr[i] == "T" {
            countT_temp += 1
        }
        suffix_T[i] = countT_temp
    }

    var suffix_CT = [Int64](repeating: 0, count: n+1)
    var countT: Int64 = 0
    var countCT: Int64 = 0
    for i in (0..<n).reversed() {
        if sArr[i] == "T" {
            countT += 1
        } else if sArr[i] == "C" {
            countCT += countT
        }
        suffix_CT[i] = countCT
    }

    var ans = base_total
    for p in 0...n {
        let new1 = suffix_CT[p]
        let candidate1 = base_total + new1

        let new2 = prefix_L[p] * suffix_T[p]
        let candidate2 = base_total + new2

        let new3 = prefix_LC[p]
        let candidate3 = base_total + new3

        ans = max(ans, candidate1, candidate2, candidate3)
    }

    return ans
}
